   299→    async commentOnPost(post, member, comment, options, createdAt) {
   300→        this.checkEnabled();
   301→        const memberModel = await this.models.Member.findOne({
   302→            id: member
   303→        }, {
   304→            require: true,
   305→            ...options,
   306→            withRelated: ['products']
   307→        });
   308→
   309→        this.checkCommentAccess(memberModel);
   310→
   311→        const postModel = await this.models.Post.findOne({
   312→            id: post
   313→        }, {
   314→            require: true,
   315→            ...options,
   316→            withRelated: ['tiers']
   317→        });
   318→
   319→        this.checkPostAccess(postModel, memberModel);
   320→
   321→        const commentData = {
   322→            post_id: post,
   323→            member_id: member,
   324→            parent_id: null,
   325→            html: comment,
   326→            status: 'published'
   327→        };
   328→
   329→        if (createdAt) {
   330→            commentData.created_at = createdAt;
   331→        }
   332→
   333→        const model = await this.models.Comment.add(commentData, options);
   334→
   335→        if (!options.context.internal) {
   336→            await this.sendNewCommentNotifications(model);
   337→        }
