   349→    /**
   350→     * @param {string} parent - The ID of the Comment to reply to
   351→     * @param {string} inReplyTo - The ID of the Reply to reply to
   352→     * @param {string} member - The ID of the Member to comment as
   353→     * @param {string} comment - The HTML content of the Comment
   354→     * @param {any} options
   355→     * @param {Date} [createdAt] - Optional custom created_at timestamp
   356→     */
   357→    async replyToComment(parent, inReplyTo, member, comment, options, createdAt) {
   358→        this.checkEnabled();
   359→        const memberModel = await this.models.Member.findOne({
   360→            id: member
   361→        }, {
   362→            require: true,
   363→            ...options,
   364→            withRelated: ['products']
   365→        });
   366→
   367→        this.checkCommentAccess(memberModel);
   368→
   369→        const parentComment = await this.getCommentByID(parent, options);
   370→        if (!parentComment) {
   371→            throw new errors.BadRequestError({
   372→                message: tpl(messages.commentNotFound)
   373→            });
   374→        }
   375→
   376→        if (parentComment.get('parent_id') !== null) {
   377→            throw new errors.BadRequestError({
   378→                message: tpl(messages.replyToReply)
   379→            });
   380→        }
   381→
   382→        const postModel = await this.models.Post.findOne({
   383→            id: parentComment.get('post_id')
   384→        }, {
   385→            require: true,
   386→            ...options,
   387→            withRelated: ['tiers']
   388→        });
   389→
   390→        this.checkPostAccess(postModel, memberModel);
   391→
   392→        let inReplyToComment;
   393→        if (parent && inReplyTo) {
   394→            inReplyToComment = await this.getCommentByID(inReplyTo, options);
   395→
   396→            // we only allow references to published comments to avoid leaking
   397→            // hidden data via the snippet included in API responses
   398→            if (inReplyToComment && inReplyToComment.get('status') !== 'published') {
   399→                inReplyToComment = null;
   400→            }
   401→
   402→            // we don't allow in_reply_to references across different parents
   403→            if (inReplyToComment && inReplyToComment.get('parent_id') !== parent) {
   404→                inReplyToComment = null;
   405→            }
   406→        }
   407→
   408→        const commentData = {
   409→            post_id: parentComment.get('post_id'),
   410→            member_id: member,
   411→            parent_id: parentComment.id,
   412→            in_reply_to_id: inReplyToComment && inReplyToComment.get('id'),
   413→            html: comment,
   414→            status: 'published'
   415→        };
   416→
   417→        if (createdAt) {
   418→            commentData.created_at = createdAt;
   419→        }
   420→
   421→        const model = await this.models.Comment.add(commentData, options);
   422→
   423→        if (!options.context.internal) {
   424→            await this.sendNewCommentNotifications(model);
   425→        }
   426→
   427→        DomainEvents.dispatch(MemberCommentEvent.create({
   428→            memberId: member,
   429→            postId: parentComment.get('post_id'),
   430→            commentId: model.id
   431→        }));
   432→
   433→        // Instead of returning the model, fetch it again, so we have all the relations properly fetched
   434→        return await this.models.Comment.findOne({id: model.id}, {...options, require: true});
   435→    }
