   442→    async deleteComment(id, member, options) {
   443→        this.checkEnabled();
   444→        const existingComment = await this.getCommentByID(id, options);
   445→
   446→        if (existingComment.get('member_id') !== member) {
   447→            throw new errors.NoPermissionError({
