   464→    /**
   465→     * @param {string} id - The ID of the Comment to edit
   466→     * @param {string} member - The ID of the Member to edit as
   467→     * @param {string} comment - The new HTML content of the Comment
   468→     * @param {any} options
   469→     */
   470→    async editCommentContent(id, member, comment, options) {
   471→        this.checkEnabled();
   472→        const existingComment = await this.getCommentByID(id, options);
   473→
   474→        if (!comment) {
   475→            return existingComment;
   476→        }
   477→
   478→        if (existingComment.get('member_id') !== member) {
   479→            throw new errors.NoPermissionError({
   480→                message: tpl(messages.cannotEditComment)
   481→            });
   482→        }
   483→
   484→        const model = await this.models.Comment.edit({
   485→            html: comment,
   486→            edited_at: new Date()
   487→        }, {
   488→            id,
   489→            require: true,
   490→            ...options
   491→        });
   492→
   493→        return model;
   494→    }
