   496→    /**
   497→     * Bulk update comment status based on NQL filter
   498→     * @param {string} filter - NQL filter string (e.g., "member_id:'abc123'+status:published")
   499→     * @param {string} status - New status ('hidden', 'published', 'deleted')
   500→     */
   501→    async bulkUpdateStatus(filter, status) {
   502→        await this.models.Comment.bulkEditWhere({
   503→            data: {status},
   504→            where: byNQL(filter)
   505→        });
   506→    }
   507→
   508→    async getMemberIdByUUID(uuid, options) {
   509→        const member = await this.models.Member.findOne({uuid}, options);
   510→
   511→        if (!member) {
   512→            throw new errors.NotFoundError({
   513→                message: tpl(messages.memberNotFound)
   514→            });
   515→        }
   516→
   517→        return member.id;
   518→    }
   519→}
